  (12, 'Mark 11:15-17', 1),
  (12, 'Luke 19:45-46', 2),
  (12, 'John 2:13-17', 3),
  (12, 'Leviticus 12:8', 4),
  (13, 'Isaiah 56:7', 1),
  (13, 'Jeremiah 7:11', 2),
  (13, 'Malachi 3:1-3', 3),
  (14, '2 Samuel 5:8', 1),
  (14, 'Isaiah 35:5-6', 2),
  (15, 'Matthew 19:14', 1),
  (15, 'Luke 19:39-40', 2),
  (16, 'Psalm 8:2', 1),
  (16, '1 Corinthians 1:27', 2),
  (17, 'John 11:1', 1),
  (17, 'Matthew 26:6', 2),
  (18, 'Hebrews 4:15', 1),
  (18, 'Mark 11:12-14', 2),
  (19, 'Hosea 9:10', 1),
  (19, 'Joel 1:7', 2),
  (19, 'Micah 7:1', 3),
